ee:message.ee:set-payload:
%dw 2.0
output application/json
---
if (payload.employee_data? and !isEmpty(payload.employee_data))
    payload.employee_data map (emp) ->
        emp mapObject (value, key) -> {
            (key) :
                if (typeOf(value) == Array)
                    (value map (item) ->
                        if (typeOf(item) == Object)
                            (item pluck (v) ->
                                v as String default ""
                            ) joinBy " | "
                        else
                            item as String default ""
                    ) joinBy " || "
                else if (typeOf(value) == Object)
                    write(value, "application/json")
                else
                    value default ""
        }
else
    []

%dw 2.0
output application/json
---
do {
    var cols = payload.cols default []
    var rows = payload.'output' default []
    ---
    if (!isEmpty(cols) and !isEmpty(rows))
        rows map (row) ->
            cols zip row reduce ((pair, acc = {} as Object) ->
                acc ++ { (pair[0]) : pair[1] default null }
            )
    else
        []
}

ee:variables.ee:set-variable:
