%dw 2.0
output application/json
---
do {
    var cols = payload.cols default []
    var rows = payload.data default []
    ---
    if (!isEmpty(cols) and !isEmpty(rows))
        rows map (row, rowIndex) ->
            cols reduce ((col, acc = {} as Object) ->
                acc ++ { (col) : row[cols indexOf col] default null }
            )
    else
        []
}

